SELECT operation
FROM data_acquisition
WHERE user_id = 1;

SELECT COUNT(*)
FROM evaluation
WHERE user_id = 1 AND evaluation_status = 'completed';

SELECT user_id, COUNT(acquisition_id) AS num_operations
FROM data_acquisition
GROUP BY user_id;

SELECT COUNT(*) AS successful_acquisitions
FROM data_acquisition
WHERE acquisition_status = 'success';

SELECT SUM(CAST(REPLACE(prepped_data_size, ',', '') AS INTEGER)) AS total_prepped_data_size
FROM data_preparation
WHERE user_id = 1;
